                if (createPurchaseOrderLineRequest.SalesTaxCodeIdOption.Value != null)
                    writer.WriteString("salesTaxCodeId", createPurchaseOrderLineRequest.SalesTaxCodeId);
                else
                    writer.WriteNull("salesTaxCodeId");

            if (createPurchaseOrderLineRequest.Other1Option.IsSet)
                if (createPurchaseOrderLineRequest.Other1Option.Value != null)
                    writer.WriteString("other1", createPurchaseOrderLineRequest.Other1);
                else
                    writer.WriteNull("other1");

            if (createPurchaseOrderLineRequest.Other2Option.IsSet)
                if (createPurchaseOrderLineRequest.Other2Option.Value != null)
                    writer.WriteString("other2", createPurchaseOrderLineRequest.Other2);
                else
                    writer.WriteNull("other2");
        }
    }
